classdef ComplexLogGradientDiagnostic
    %COMPLEXLOGGRADIENTDIAGNOSTIC Branch-free gradient residual summary.
    %
    % This class is diagnostic only. Weak gradients, nonfinite samples, and
    % nonpositive weights or geometric scales remain explicitly invalid.
    % Traceability: algo/main.tex Secs. 9.1-9.4, Eqs. (110)-(120).

    methods (Static)
        function result = analyze(gr, gt, options)
            arguments
                gr (:, 1) double
                gt (:, 1) double {mustHaveSameRows(gt, gr)}
                options.Weights (:, 1) double ...
                    {mustBeFinite, mustBeNonnegative, ...
                    mustHaveOneOrNRows(options.Weights, gr)} = ones(1, 1)
                options.ValidMask (:, 1) logical ...
                    {mustHaveOneOrNRows(options.ValidMask, gr)} = true(1, 1)
                options.GeometricScale (:, 1) double ...
                    {mustBeFinite, mustBePositive, ...
                    mustHaveOneOrNRows(options.GeometricScale, gr)} = ones(1, 1)
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e-6
                options.EpsilonGradient (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e-12
                options.AmplitudeWeight (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1
                options.PhaseWeight (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1
            end

            n = size(gr, 1);
            w = ComplexLogGradientDiagnostic.expand(options.Weights, n);
            mask = ComplexLogGradientDiagnostic.expand(options.ValidMask, n);
            scale = ComplexLogGradientDiagnostic.expand( ...
                options.GeometricScale, n);
            finiteGradient = isfinite(real(gr)) & isfinite(imag(gr)) ...
                & isfinite(real(gt)) & isfinite(imag(gt));
            valid = mask & w > 0 & finiteGradient ...
                & abs(gr) >= options.MinimumGradient ...
                & abs(gt) >= options.MinimumGradient;

            da = nan(n, 1);
            dtheta = nan(n, 1);
            dtheta2 = nan(n, 1);
            % Eqs. (110)-(111), evaluated without an individual complex log.
            da(valid) = log((abs(gr(valid)) + options.EpsilonGradient) ...
                ./ (abs(gt(valid)) + options.EpsilonGradient));
            crossGradient = gr(valid) .* conj(gt(valid));
            dtheta(valid) = atan2(imag(crossGradient), ...
                real(crossGradient));
            % Eq. (115), polarity-invariant residual interpreted modulo pi.
            crossGradient2 = gr(valid) .^ 2 .* conj(gt(valid) .^ 2);
            dtheta2(valid) = 0.5 .* atan2(imag(crossGradient2), ...
                real(crossGradient2));

            % Eq. (120); scale=1 leaves the raw amplitude residual unchanged.
            daPhoto = da - log(scale);
            sumWeight = sum(w(valid));
            effectiveSampleCount = nnz(valid);
            if effectiveSampleCount == 0
                summary = ComplexLogGradientDiagnostic.emptySummary();
            else
                ww = w(valid);
                aa = da(valid);
                ap = daPhoto(valid);
                tt = dtheta(valid);
                tt2 = 2 .* dtheta2(valid);

                % Eqs. (112)-(113), with both raw and scale-removed gain.
                phaseMoment = sum(ww .* exp(1i .* tt));
                phaseMoment2 = sum(ww .* exp(1i .* tt2));
                rotation = angle(phaseMoment);
                rotationSpin2 = 0.5 .* angle(phaseMoment2);
                rawLogGain = sum(ww .* aa) ./ sumWeight;
                logGain = sum(ww .* ap) ./ sumWeight;
                amplitudeResidual = ap - logGain;
                phaseResidual = 1 - cos(tt - rotation);

                % Eq. (114), using a quadratic amplitude penalty and the
                % circular phase penalty directly as the two named rhos.
                residualCost = sum(ww .* (options.AmplitudeWeight ...
                    .* amplitudeResidual .^ 2 + options.PhaseWeight ...
                    .* phaseResidual)) ./ sumWeight;
                summary = struct( ...
                    "Rotation", rotation, ...
                    "Spin2Rotation", rotationSpin2, ...
                    "RawLogGain", rawLogGain, ...
                    "LogGain", logGain, ...
                    "AmplitudeResidualRms", sqrt(sum(ww ...
                    .* amplitudeResidual .^ 2) ./ sumWeight), ...
                    "PhaseResultantLength", abs(phaseMoment) ./ sumWeight, ...
                    "PhaseCircularVariance", 1 - abs(phaseMoment) ./ sumWeight, ...
                    "Spin2ResultantLength", abs(phaseMoment2) ./ sumWeight, ...
                    "Spin2CircularVariance", 1 - abs(phaseMoment2) ./ sumWeight, ...
                    "ResidualCost", residualCost, ...
                    "SummaryValid", true);
            end

            result = struct( ...
                "DeltaLogAmplitude", da, ...
                "DeltaLogPhotometric", daPhoto, ...
                "DeltaPhase", dtheta, ...
                "DeltaPhaseSpin2", dtheta2, ...
                "InputValid", valid, ...
                "InputSampleCount", n, ...
                "EffectiveSampleCount", effectiveSampleCount, ...
                "ValidFraction", effectiveSampleCount ./ max(n, 1), ...
                "WeightSum", sumWeight, ...
                "MinimumGradient", options.MinimumGradient, ...
                "GeometricScale", scale, ...
                "AmplitudeWeight", options.AmplitudeWeight, ...
                "PhaseWeight", options.PhaseWeight);
            names = fieldnames(summary);
            for k = 1:numel(names)
                result.(names{k}) = summary.(names{k});
            end
        end

        function [scale, valid] = directionalScale(a, g, options)
            %DIRECTIONALSCALE Evaluate ||A^T*n|| for n=g/||g||.
            % Traceability: algo/main.tex Sec. 9.3, Eq. (119).

            arguments
                a (:, 2, 2) double {mustBeReal}
                g (:, 1) double {mustHaveSameRows(g, a)}
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e-6
            end

            valid = all(isfinite(reshape(a, size(a, 1), [])), 2) ...
                & isfinite(real(g)) & isfinite(imag(g)) ...
                & abs(g) >= options.MinimumGradient;
            scale = nan(size(g));
            gx = real(g(valid)) ./ abs(g(valid));
            gy = imag(g(valid)) ./ abs(g(valid));
            hx = a(valid, 1, 1) .* gx + a(valid, 2, 1) .* gy;
            hy = a(valid, 1, 2) .* gx + a(valid, 2, 2) .* gy;
            scale(valid) = hypot(hx, hy);
            valid = valid & scale > 0 & isfinite(scale);
            scale(~valid) = NaN;
        end
    end

    methods (Static, Access = private)
        function x = expand(x, n)
            if size(x, 1) == 1
                x = repmat(x, n, 1);
            end
        end

        function summary = emptySummary()
            summary = struct( ...
                "Rotation", NaN, "Spin2Rotation", NaN, ...
                "RawLogGain", NaN, "LogGain", NaN, ...
                "AmplitudeResidualRms", NaN, ...
                "PhaseResultantLength", NaN, ...
                "PhaseCircularVariance", NaN, ...
                "Spin2ResultantLength", NaN, ...
                "Spin2CircularVariance", NaN, ...
                "ResidualCost", NaN, "SummaryValid", false);
        end
    end
end

function mustHaveSameRows(a, b)
if size(a, 1) ~= size(b, 1)
    error("ComplexLogGradientDiagnostic:RowCountMismatch", ...
        "Gradient inputs must have the same number of rows.");
end
end

function mustHaveOneOrNRows(a, b)
if ~(size(a, 1) == 1 || size(a, 1) == size(b, 1))
    error("ComplexLogGradientDiagnostic:RowCountMismatch", ...
        "An option must have one row or one row per gradient sample.");
end
end
